const costingMethod = {{node:code_node_wBfvXM2G.data.costingMethod}};
const fifoData = {{node:search_node_L50IlXls.data.data}};
const waData = {{node:search_node_FGjULf7c.data.data}};
const plantId = {{workflowparams:plant_id}};
const organizationId = {{workflowparams:organization_id}};
const materialId = {{workflowparams:material_id}};
const batchId = {{workflowparams:batch_id}};

const formatNumber = (value) => {
  if (value === null || value === undefined || value === "") return 0;
  return parseFloat(value).toFixed(3);
};

const formatPrice = (value) => {
  if (value === null || value === undefined || value === "") return 0;
  return parseFloat(value).toFixed(4);
};

const fifoRecords = Array.isArray(fifoData) ? fifoData : [];
const waRecords = Array.isArray(waData) ? waData : [];

// TARGET: Weighted Average - merge FIFO into existing WA
if (costingMethod === "Weighted Average") {
  const idsToDelete = fifoRecords.filter((r) => r.id).map((r) => r.id);

  // Calculate weighted average from FIFO
  let fifoTotalQty = 0;
  let fifoTotalCost = 0;
  for (const record of fifoRecords) {
    const qty = parseFloat(record.fifo_available_quantity) || 0;
    if (qty > 0) {
      const price = parseFloat(record.fifo_cost_price) || 0;
      fifoTotalQty += qty;
      fifoTotalCost += qty * price;
    }
  }
  const fifoAvgCost = fifoTotalQty > 0 ? fifoTotalCost / fifoTotalQty : 0;

  // Merge with existing WA
  const existingWa = waRecords[0];
  const existingWaQty = parseFloat(existingWa.wa_quantity) || 0;
  const existingWaCost = parseFloat(existingWa.wa_cost_price) || 0;
  const newTotalQty = existingWaQty + fifoTotalQty;
  const newWaCost =
    newTotalQty > 0
      ? (existingWaCost * existingWaQty + fifoAvgCost * fifoTotalQty) / newTotalQty
      : existingWaCost;

  return {
    targetRecord: {
      id: existingWa.id,
      wa_quantity: formatNumber(newTotalQty),
      wa_cost_price: formatPrice(newWaCost),
      updated_at: new Date(),
    },
    idsToDelete: idsToDelete,
    targetCosting: "WA",
  };
}

// TARGET: FIFO - add WA as new layer
if (costingMethod === "First In First Out") {
  const idsToDelete = waRecords.filter((r) => r.id).map((r) => r.id);

  const sortedWa = waRecords.sort((a, b) => {
    const dateA = a.created_at ? new Date(a.created_at) : new Date(0);
    const dateB = b.created_at ? new Date(b.created_at) : new Date(0);
    return dateB - dateA;
  });
  const waQty = parseFloat(sortedWa[0].wa_quantity) || 0;
  const waCost = parseFloat(sortedWa[0].wa_cost_price) || 0;

  const maxSequence = Math.max(
    ...fifoRecords.map((r) => parseInt(r.fifo_sequence || 0, 10)),
    0,
  );

  const targetRecord = {
    material_id: materialId,
    plant_id: plantId,
    organization_id: organizationId,
    fifo_sequence: maxSequence + 1,
    fifo_cost_price: formatPrice(waCost),
    fifo_initial_quantity: formatNumber(waQty),
    fifo_available_quantity: formatNumber(waQty),
    batch_id: null,
    created_at: new Date(),
  };

  if (batchId) {
    targetRecord.batch_id = batchId;
  }

  return {
    targetRecord: targetRecord,
    idsToDelete: idsToDelete,
    targetCosting: "FIFO",
  };
}

return {
  targetRecord: null,
  idsToDelete: [],
  targetCosting: null,
};

